tool.command:
exec 3>&1 4>&2; exec > enzywizard.log 2>&1;
MSMS_EXE=\$(command -v msms || command -v msms.x86_64Linux2.2.6.1 || true); if [ -n "\$MSMS_EXE" ]; then mkdir -p "\$HOME"; echo "set pyvol_msms_exe, \$MSMS_EXE" > "\$HOME/.pymolrc"; fi;
#set $wt_name = $wt_cleaned_input_path.element_identifier #set $mut_name = $mut_cleaned_input_path.element_identifier #set $wt_msa_name = $wt_input_msa.element_identifier #set $mut_msa_name = $mut_input_msa.element_identifier ln -s '$wt_cleaned_input_path' '$wt_name' && ln -s '$mut_cleaned_input_path' '$mut_name' && ln -s '$wt_input_msa' '$wt_msa_name' && ln -s '$mut_input_msa' '$mut_msa_name' && enzywizard-mut-batch -w '$wt_name' -m '$mut_name' -wm '$wt_msa_name' -mm '$mut_msa_name' -a '$cleaned_amino_acid_substitution' #if $advanced.substrate_names: -s '$advanced.substrate_names' #end if -wo wt_output -mo mut_output $advanced.save_extra_outputs --hydrocluster_cutoff '$advanced.hydrocluster_cutoff' $advanced.no_minimize_energy --energy_minimization_iteration '$advanced.minimization_iteration' --flexibility_method '$advanced.flexibility_method' --flexibility_cutoff '$advanced.flexibility_cutoff' --flexibility_n_modes '$advanced.flexibility_n_modes' --disorder_window_size '$advanced.disorder_window_size' --disorder_min_region_length '$advanced.disorder_min_region_length' --embedding_model_name '$advanced.embedding_model_name' --pocket_min_rad '$advanced.pocket_min_rad' --pocket_max_rad '$advanced.pocket_max_rad' --pocket_min_volume '$advanced.pocket_min_volume' --substrate_max_synonyms '$advanced.substrate_max_synonyms' --substrate_fp_radius '$advanced.substrate_fp_radius' --substrate_n_bits '$advanced.substrate_n_bits' --substrate_num_confs '$advanced.substrate_num_confs' --substrate_prune_rms '$advanced.substrate_prune_rms' --dock_max_attempt_num '$advanced.dock_max_attempt_num' $advanced.dock_no_early_stop --dock_exhaustiveness '$advanced.dock_exhaustiveness' --dock_cpu "\${GALAXY_SLOTS:-1}" #if $advanced.dock_catalytic_residue: --dock_catalytic_residue '$advanced.dock_catalytic_residue' #end if #if $advanced.dock_catalytic_site_coord: --dock_catalytic_site_coord '$advanced.dock_catalytic_site_coord' #end if #if $advanced.dock_box_size: --dock_box_size '$advanced.dock_box_size' #end if --hbond_bonded_h_min_distance '$advanced.hbond_bonded_h_min_distance' --hbond_bonded_h_max_distance '$advanced.hbond_bonded_h_max_distance' --hbond_da_max_distance '$advanced.hbond_da_max_distance' --hbond_ha_max_distance '$advanced.hbond_ha_max_distance' --hbond_angle '$advanced.hbond_angle' --ionic_distance_cutoff '$advanced.ionic_distance_cutoff' --vdw_mu '$advanced.vdw_mu' --ppstack_center_distance_cutoff '$advanced.ppstack_center_distance_cutoff' --pication_distance_cutoff '$advanced.pication_distance_cutoff' --pication_angle_cutoff '$advanced.pication_angle_cutoff' --ssbond_max_distance '$advanced.ssbond_max_distance' ; status=\$?; echo "---- files in Galaxy job working directory ----" >&4; find . -maxdepth 5 -type f | sort >&4; if [ "\$status" -ne 0 ]; then cat enzywizard.log >&4; exit "\$status"; fi; if ! find wt_output mut_output -maxdepth 2 -type f -name '*.json' | grep -q .; then echo "No EnzyWizard Mut Batch output JSON files were produced." >&4; cat enzywizard.log >&4; [ -f log.txt ] && cat log.txt >&4; exit 1; fi;
